// ═══════════════════════════════════════════════════════
// MISSION PICKER FUNCTION
// ═══════════════════════════════════════════════════════

export function pickMissions(count = 3, weaponId = null, forceEvent = false) {
  const weights = (weaponId && WEAPON_CATEGORY_WEIGHTS[weaponId])
    ? WEAPON_CATEGORY_WEIGHTS[weaponId]
    : { creative: 20, educational: 20, domestic: 20, student: 20, leisure: 20 };

  // Separate event and regular missions
  const eventPool   = MISSION_BANK.filter(m => m.isEvent);
  const regularPool = MISSION_BANK.filter(m => !m.isEvent);

  const results = [];
  const usedIndices = new Set();

  for (let i = 0; i < count; i++) {
    const isEvent = forceEvent || Math.random() < 0.15;

    if (isEvent && eventPool.length > 0) {
      // Pick random event mission
      let idx;
      let attempts = 0;
      do {
        idx = Math.floor(Math.random() * eventPool.length);
        attempts++;
      } while (usedIndices.has("e" + idx) && attempts < 20);
      usedIndices.add("e" + idx);
      results.push({ ...eventPool[idx] });
    } else {
      // Weighted category pick
      const totalWeight = Object.values(weights).reduce((a, b) => a + b, 0);
      let rand = Math.random() * totalWeight;
      let category = "creative";
      for (const [cat, w] of Object.entries(weights)) {
        if (!["creative","educational","domestic","student","leisure"].includes(cat)) continue;
        rand -= w;
        if (rand <= 0) { category = cat; break; }
      }

      const pool = regularPool.filter(m => m.category === category);
      if (pool.length === 0) {
        // Fallback: any regular mission
        const fallback = regularPool[Math.floor(Math.random() * regularPool.length)];
        results.push({ ...fallback });
        continue;
      }

      let idx;
      let attempts = 0;
      do {
        idx = Math.floor(Math.random() * pool.length);
        attempts++;
      } while (usedIndices.has(category + idx) && attempts < 30);
      usedIndices.add(category + idx);
      results.push({ ...pool[idx] });
    }
  }

  return results;
}
